# Find the variables that contain our data
clinical_result = None
mutation_result = None

# Check all variables to find the ones with our data
for var_name, var_value in globals().items():
    if 'query_db' in str(var_name) and '_50' in str(var_name):
        clinical_result = var_value
    if 'query_db' in str(var_name) and '_58' in str(var_name):
        mutation_result = var_value

# If not found in globals, try direct access
if not clinical_result:
    try:
        clinical_result = globals()['var_functions.query_db_50']
    except:
        pass

if not mutation_result:
    try:
        mutation_result = globals()['var_functions.query_db_58']
    except:
        pass

print('__RESULT__:')
print(json.dumps({
    'clinical_found': clinical_result is not None,
    'mutation_found': mutation_result is not None,
    'clinical_type': str(type(clinical_result)),
    'mutation_type': str(type(mutation_result))
}))

